  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SIPResults {
  totalInvested: number;
  estimatedReturns: number;
  totalValue: number;
  yearlyData: GrowthDataPoint[];
}

export interface GrowthDataPoint {
  year: number;
  invested: number;
  totalValue: number;
}

export interface SIPInputs {
  monthlyInvestment: number;
  expectedReturn: number;
  periodYears: number;
}

import { SIPInputs, SIPResults, GrowthDataPoint } from '../types';

/**
 * Calculates SIP future value and growth trajectory.
 * Formula: FV = P × ({[1 + i]^n – 1} / i) × (1 + i)
 * Where:
 * P = Monthly investment amount
 * i = Monthly rate of interest (Annual rate / 12 / 100)
 * n = Number of months
 */
export const calculateSIP = (inputs: SIPInputs): SIPResults => {
  const { monthlyInvestment, expectedReturn, periodYears } = inputs;
  const monthlyRate = expectedReturn / 12 / 100;
  const totalMonths = periodYears * 12;

  const yearlyData: GrowthDataPoint[] = [];

  // Calculate year by year for chart
  for (let year = 1; year <= periodYears; year++) {
    const months = year * 12;
    const invested = monthlyInvestment * months;

    // SIP Future Value formula
    const futureValue = monthlyInvestment * 
      ((Math.pow(1 + monthlyRate, months) - 1) / monthlyRate) * 
      (1 + monthlyRate);

    yearlyData.push({
      year,
      invested: Math.round(invested),
      totalValue: Math.round(futureValue),
    });
  }

  const lastYear = yearlyData[yearlyData.length - 1];
  const totalInvested = monthlyInvestment * totalMonths;
  const totalValue = lastYear ? lastYear.totalValue : 0;
  const estimatedReturns = totalValue - totalInvested;

  return {
    totalInvested: Math.round(totalInvested),
    estimatedReturns: Math.round(estimatedReturns),
    totalValue: Math.round(totalValue),
    yearlyData,
  };
};

export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(value);
};

import { GoogleGenAI } from "@google/genai";
import { SIPInputs, SIPResults } from "../types";

export const getFinancialInsights = async (inputs: SIPInputs, results: SIPResults): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Act as a senior financial advisor. I am planning a Systematic Investment Plan (SIP).
    Here are my details:
    - Monthly Investment: $${inputs.monthlyInvestment}
    - Expected Annual Return: ${inputs.expectedReturn}%
    - Investment Horizon: ${inputs.periodYears} years

    Calculated Results:
    - Total Invested: $${results.totalInvested}
    - Estimated Returns: $${results.estimatedReturns}
    - Final Maturity Value: $${results.totalValue}

    Please provide:
    1. A brief analysis of this wealth accumulation plan.
    2. One "Pro Tip" to reach a 20% higher goal.
    3. A realistic warning or consideration (e.g., inflation, market volatility).

    Keep the tone encouraging, professional, and concise (max 200 words). Use bullet points.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Unable to generate insights at this moment.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "The AI financial advisor is currently offline. Please check your connection and try again.";
  }
};

