 * n = Number of months
 */
export const calculateSIP = (inputs: SIPInputs): SIPResults => {
  const { monthlyInvestment, expectedReturn, periodYears } = inputs;
  const monthlyRate = expectedReturn / 12 / 100;
  const totalMonths = periodYears * 12;

  const yearlyData: GrowthDataPoint[] = [];

