import { GoogleGenAI } from "@google/genai";
import { SIPInputs, SIPResults } from "../types";

export const getFinancialInsights = async (inputs: SIPInputs, results: SIPResults): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const frequencyText = inputs.mode === 'SIP' ? `${inputs.frequency} SIP` : 'One-time Lumpsum';

  const prompt = `
    Act as a senior Indian financial advisor. I am planning a ${inputs.mode} investment in Indian Rupees (₹).
    Here are my details:
    - Investment Type: ${frequencyText}
    - Amount: ₹${inputs.investmentAmount.toLocaleString('en-IN')}
    - Expected Annual Return: ${inputs.expectedReturn}%
    - Investment Horizon: ${inputs.periodYears} years

    Calculated Results:
    - Total Invested: ₹${results.totalInvested.toLocaleString('en-IN')}
    - Estimated Returns: ₹${results.estimatedReturns.toLocaleString('en-IN')}
    - Final Maturity Value: ₹${results.totalValue.toLocaleString('en-IN')}

    Please provide:
    1. A brief analysis of this ${inputs.mode} (${inputs.frequency} frequency) wealth accumulation plan in the context of Indian market trends.
    2. One "Pro Tip" for an Indian investor specifically regarding their ${inputs.frequency} commitment.
    3. A realistic warning or consideration (e.g., taxation or inflation impact).

    Keep the tone encouraging, professional, and concise (max 180 words). Use bullet points. Use ₹ symbol.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Unable to generate insights at this moment.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "The AI financial advisor is currently offline. Please check your connection.";
  }
};

