                )}
              </div>
            )}

            {/* Summary Text */}
            <div className={`p-6 rounded-2xl border transition-colors ${darkMode ? 'bg-emerald-950/20 border-emerald-900/50' : 'bg-emerald-50 border-emerald-100'}`}>
              <h4 className={`font-bold mb-2 uppercase tracking-wider text-xs ${darkMode ? 'text-emerald-400' : 'text-emerald-800'}`}>{inputs.mode} Summary</h4>
              <p className={`text-sm leading-relaxed ${darkMode ? 'text-emerald-300/80' : 'text-emerald-700'}`}>
                By investing <span className={`font-bold ${darkMode ? 'text-emerald-400' : 'text-emerald-900'}`}>₹{inputs.investmentAmount.toLocaleString('en-IN')}</span> {inputs.mode === 'SIP' ? inputs.frequency.toLowerCase() : 'once'} for <span className={`font-bold ${darkMode ? 'text-emerald-400' : 'text-emerald-900'}`}>{inputs.periodYears} years</span>, 
                you'll accumulate a total corpus of <span className={`font-bold text-lg ${darkMode ? 'text-indigo-400' : 'text-emerald-900'}`}>₹{results.totalValue.toLocaleString('en-IN')}</span>. 
                Your wealth will grow by <span className={`font-bold ${darkMode ? 'text-emerald-400' : 'text-emerald-900'}`}>₹{results.estimatedReturns.toLocaleString('en-IN')}</span> over your principal investment.
              </p>
            </div>
          </div>
        </div>
      </main>

      <footer className="max-w-6xl mx-auto px-4 mt-12 text-center text-slate-400 text-xs pb-10">
        <p className="mb-2">Built with ❤️ for Indian Investors</p>
        <p>© {new Date().getFullYear()} Bharat Wealth. All calculations are for illustrative purposes. Mutual fund investments are subject to market risks.</p>
      </footer>
    </div>
  );
};

