        <div className="p-6 rounded-2xl shadow-sm border transition-all hover:shadow-md dark:bg-slate-900 dark:border-slate-800 bg-white border-slate-100">
          <h3 className="text-lg font-bold dark:text-slate-100 text-slate-800 mb-4 flex items-center gap-2">
            <span className="w-1 h-4 bg-emerald-500 rounded-full"></span>
            Wealth Composition
          </h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={8}
                  dataKey="value"
                  animationBegin={0}
                  animationDuration={1500}
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} strokeWidth={0} />
                  ))}
                </Pie>
                <Tooltip 
                  formatter={(value: number) => `₹${value.toLocaleString('en-IN')}`}
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Growth Projection (Area) */}
        <div className="p-6 rounded-2xl shadow-sm border transition-all hover:shadow-md dark:bg-slate-900 dark:border-slate-800 bg-white border-slate-100">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
            <h3 className="text-lg font-bold dark:text-slate-100 text-slate-800 flex items-center gap-2">
              <span className="w-1 h-4 bg-indigo-500 rounded-full"></span>
              Growth Projection
            </h3>

            <button 
              onClick={() => setShowInvestedLine(!showInvestedLine)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                showInvestedLine 
                  ? 'dark:bg-slate-800 dark:text-slate-400 bg-slate-100 text-slate-700 hover:bg-slate-200' 
