import React, { useState, useMemo, useEffect, useRef } from 'react';
import { SIPInputs, SIPResults } from './types';
import { calculateWealth } from './utils/sipCalculations';
import { getFinancialInsights } from './services/geminiService';
import InputSection from './components/InputSection';
import ResultCards from './components/ResultCards';
import ChartsSection from './components/ChartsSection';
import html2canvas from 'html2canvas';

const App: React.FC = () => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [darkMode, setDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark';
    }
    return false;
  });

  const [inputs, setInputs] = useState<SIPInputs>({
    investmentAmount: 5000,
    expectedReturn: 12,
    periodYears: 10,
    mode: 'SIP',
    frequency: 'Monthly'
  });

  const [aiInsight, setAiInsight] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [isCapturing, setIsCapturing] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [darkMode]);

  const results = useMemo(() => calculateWealth(inputs), [inputs]);

  const handleGetInsights = async () => {
    setIsGenerating(true);
    setAiInsight("");
    try {
      const insight = await getFinancialInsights(inputs, results);
      setAiInsight(insight);
    } catch (error) {
      setAiInsight("Unable to connect to AI advisor. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownloadImage = async () => {
    if (!reportRef.current) return;
    setIsCapturing(true);

    // Slight delay to ensure charts are fully rendered
    setTimeout(async () => {
      try {
        const canvas = await html2canvas(reportRef.current!, {
          backgroundColor: darkMode ? '#0f172a' : '#f8fafc',
          scale: 2, // High quality
          logging: false,
          useCORS: true,
          ignoreElements: (element) => element.classList.contains('screenshot-hide'),
        });

        const image = canvas.toDataURL("image/png", 1.0);
        const link = document.createElement('a');
        link.download = `BharatWealth_${inputs.mode}_Plan.png`;
        link.href = image;
        link.click();
      } catch (err) {
        console.error("Failed to capture image:", err);
      } finally {
        setIsCapturing(false);
      }
    }, 100);
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${darkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'} pb-20`}>
      {/* Header */}
      <header className={`border-b transition-colors duration-300 sticky top-0 z-50 ${darkMode ? 'bg-slate-900/80 border-slate-800' : 'bg-white/80 border-slate-200'} backdrop-blur-md`}>
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 group cursor-pointer">
            <div className="relative w-9 h-9">
              <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-sm">
                <defs>
                  <linearGradient id="logoGradient" x1="0%" y1="0%" x2="100%" y2="100%">
                    <stop offset="0%" stopColor="#f59e0b" />
                    <stop offset="100%" stopColor="#ea580c" />
                  </linearGradient>
                </defs>
                <path 
                  d="M20 20 C20 20 50 10 80 20 L80 50 C80 75 50 90 50 90 C50 90 20 75 20 50 Z" 
                  fill="none" 
                  stroke="url(#logoGradient)" 
                  strokeWidth="8" 
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
                <path 
                  d="M35 60 L50 75 L90 25 M90 25 L75 25 M90 25 L90 40" 
                  fill="none" 
                  stroke="url(#logoGradient)" 
                  strokeWidth="10" 
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </div>
            <h1 className="text-2xl font-black tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-orange-600 to-indigo-500">
              Bharat Wealth
            </h1>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className={`p-2 rounded-xl transition-all ${darkMode ? 'bg-slate-800 text-amber-400' : 'bg-slate-100 text-slate-500'} hover:scale-110 active:scale-95`}
              aria-label="Toggle Dark Mode"
            >
              {darkMode ? (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 9h-1m15.364-6.364l-.707.707M6.343 17.657l-.707.707M16.95 16.95l.707.707M7.05 7.05l.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
                </svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
                </svg>
              )}
