import React from 'react';
import { SIPInputs, CalculationMode, Frequency } from '../types';

interface Props {
  inputs: SIPInputs;
  setInputs: (inputs: SIPInputs) => void;
  onReset: () => void;
}

const InputSection: React.FC<Props> = ({ inputs, setInputs, onReset }) => {
  const handleValueChange = (name: keyof Omit<SIPInputs, 'mode' | 'frequency'>, value: number) => {
    const safeValue = isNaN(value) ? 0 : value;
    setInputs({ ...inputs, [name]: safeValue });
  };

  const handleModeChange = (mode: CalculationMode) => {
    const investmentAmount = mode === 'SIP' ? 5000 : 100000;
    setInputs({ ...inputs, mode, investmentAmount });
  };

  const handleFrequencyChange = (frequency: Frequency) => {
    setInputs({ ...inputs, frequency });
  };

  const frequencies: Frequency[] = ['Daily', 'Weekly', 'Monthly', 'Quarterly'];

  return (
    <div className="space-y-6 p-6 rounded-2xl shadow-sm border transition-all duration-300 dark:bg-slate-900 dark:border-slate-800 bg-white border-slate-100 hover:shadow-md">
      {/* Mode Switcher */}
      <div className="flex p-1 rounded-xl dark:bg-slate-800 bg-slate-100">
        <button
          onClick={() => handleModeChange('SIP')}
          className={`flex-1 py-2 px-4 rounded-lg text-sm font-bold transition-all duration-200 ${
            inputs.mode === 'SIP' 
              ? 'dark:bg-slate-700 bg-white dark:text-indigo-400 text-indigo-600 shadow-sm' 
              : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
          }`}
        >
          SIP
        </button>
        <button
          onClick={() => handleModeChange('Lumpsum')}
          className={`flex-1 py-2 px-4 rounded-lg text-sm font-bold transition-all duration-200 ${
            inputs.mode === 'Lumpsum' 
              ? 'dark:bg-slate-700 bg-white dark:text-indigo-400 text-indigo-600 shadow-sm' 
              : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
          }`}
        >
          Lumpsum
        </button>
      </div>

      <div className="flex items-center justify-between pt-2">
        <div className="flex items-center gap-3">
          <div className="w-1 h-6 bg-indigo-600 rounded-full"></div>
          <h2 className="text-xl font-extrabold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-indigo-500 to-indigo-400">
            Investment Details
          </h2>
        </div>
        <button 
          onClick={onReset}
          className="text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-lg border dark:border-slate-800 border-slate-200 dark:text-slate-400 text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
