          Reset
        </button>
      </div>

      {inputs.mode === 'SIP' && (
        <div className="space-y-2">
          <label className="text-xs font-bold uppercase tracking-wider text-slate-400">Investment Frequency</label>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
            {frequencies.map((freq) => (
              <button
                key={freq}
                onClick={() => handleFrequencyChange(freq)}
                className={`py-2 px-1 rounded-lg text-xs font-bold border transition-all duration-200 ${
                  inputs.frequency === freq
                    ? 'bg-indigo-600 text-white border-indigo-600 shadow-md ring-2 ring-indigo-100 dark:ring-indigo-900/50'
                    : 'dark:bg-slate-800 bg-white dark:text-slate-400 text-slate-500 dark:border-slate-700 border-slate-200 hover:border-indigo-300'
                }`}
              >
                {freq}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Investment Amount */}
      <div className="space-y-4">
