          <div className="flex items-center px-3 py-1 rounded-xl border transition-all duration-200 dark:bg-emerald-950/30 dark:border-emerald-900/50 dark:focus-within:ring-emerald-900/30 bg-emerald-50 border-emerald-100 focus-within:ring-4 focus-within:ring-emerald-100">
