              type="number"
              value={inputs.expectedReturn}
              step="0.1"
              onChange={(e) => handleValueChange('expectedReturn', Number(e.target.value))}
              className="w-14 bg-transparent text-lg font-black dark:text-emerald-400 text-emerald-700 border-none outline-none text-right [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
            />
            <span className="text-emerald-500 font-bold ml-1">%</span>
          </div>
        </div>
        <input
          type="range"
          min="1"
          max="30"
          step="0.1"
          value={inputs.expectedReturn}
          onChange={(e) => handleValueChange('expectedReturn', Number(e.target.value))}
          className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-full appearance-none cursor-pointer accent-emerald-500"
        />
        <div className="flex justify-between text-[10px] font-bold uppercase text-slate-400">
          <span>1%</span>
          <span>30%</span>
        </div>
      </div>

      {/* Period */}
      <div className="space-y-4">
        <div className="flex justify-between items-center">
          <label className="text-sm font-semibold dark:text-slate-300 text-slate-600">Time Period (Years)</label>
          <div className="flex items-center px-3 py-1 rounded-xl border transition-all duration-200 dark:bg-amber-950/30 dark:border-amber-900/50 dark:focus-within:ring-amber-900/30 bg-amber-50 border-amber-100 focus-within:ring-4 focus-within:ring-amber-100">
            <input
              type="number"
              value={inputs.periodYears}
              onChange={(e) => handleValueChange('periodYears', Number(e.target.value))}
              className="w-10 bg-transparent text-lg font-black dark:text-amber-400 text-amber-700 border-none outline-none text-right [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
            />
