                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Analyzing...
                  </>
                ) : (
                  `Analyze ${inputs.mode} Plan`
                )}
              </button>
            </div>
          </div>

          {/* Right Column: Results & Analysis (THE REPORT) */}
          <div 
            className="lg:col-span-8 space-y-8 rounded-3xl" 
            ref={reportRef}
            id="professional-report-container"
          >
            {/* Professional Report Header - Controlled via 'onclone' for zero UI flicker */}
            <div id="report-header-professional" style={{ display: 'none' }} className="flex-col gap-6 pb-8 border-b border-slate-200 dark:border-slate-800">
