import React, { useState, useMemo, useEffect, useRef } from 'react';
import { SIPInputs, SIPResults, AIInsight } from './types';
import { calculateWealth } from './utils/sipCalculations';
import { getFinancialInsights } from './services/geminiService';
import InputSection from './components/InputSection';
import ResultCards from './components/ResultCards';
import ChartsSection from './components/ChartsSection';
import OnboardingGuide from './components/OnboardingGuide';
import html2canvas from 'html2canvas';

const DEFAULT_INPUTS: SIPInputs = {
  investmentAmount: 5000,
  expectedReturn: 12,
  periodYears: 10,
  mode: 'SIP',
  frequency: 'Monthly'
};

const App: React.FC = () => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [darkMode, setDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark';
    }
    return false;
  });

  const [inputs, setInputs] = useState<SIPInputs>(DEFAULT_INPUTS);

  const [aiInsight, setAiInsight] = useState<AIInsight | null>(null);
  const [aiError, setAiError] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isCapturing, setIsCapturing] = useState(false);
  const [showGuide, setShowGuide] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [darkMode]);

  const results = useMemo(() => calculateWealth(inputs), [inputs]);

  const handleGetInsights = async () => {
    setIsGenerating(true);
    setAiInsight(null);
    setAiError(null);
    try {
      const insight = await getFinancialInsights(inputs, results);
      if (insight) {
        setAiInsight(insight);
      } else {
        setAiError("Unable to connect to AI advisor. Please try again.");
      }
    } catch (error) {
      setAiError("Unable to connect to AI advisor. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleReset = () => {
    setInputs(DEFAULT_INPUTS);
    setAiInsight(null);
    setAiError(null);
  };

  const handleDownloadImage = async () => {
    if (!reportRef.current || isCapturing) return;
    setIsCapturing(true);

    requestAnimationFrame(() => {
      setTimeout(async () => {
        try {
          const canvas = await html2canvas(reportRef.current!, {
            backgroundColor: darkMode ? '#111827' : '#ffffff',
            scale: 2,
            logging: false,
            useCORS: true,
            allowTaint: true,
            onclone: (clonedDoc) => {
              const clonedContainer = clonedDoc.getElementById('professional-report-container');
              const clonedProHeader = clonedDoc.getElementById('report-header-professional');

              if (clonedContainer) {
                clonedContainer.style.padding = '48px';
                clonedContainer.style.borderRadius = '0px';
                clonedContainer.style.backgroundColor = darkMode ? '#111827' : '#ffffff';

                if (clonedProHeader) {
                  clonedProHeader.style.display = 'flex';
                  clonedProHeader.style.marginBottom = '32px';
                }

                const screenshotHides = clonedDoc.querySelectorAll('.screenshot-hide');
                screenshotHides.forEach(el => (el as HTMLElement).style.display = 'none');
              }
            }
          });

          const image = canvas.toDataURL("image/png", 0.95);
          const link = document.createElement('a');
          link.download = `BharatWealth_${inputs.mode}_Report_${new Date().toISOString().split('T')[0]}.png`;
          link.href = image;
          link.click();
        } catch (err) {
          console.error("Professional report capture failed:", err);
        } finally {
          setIsCapturing(false);
        }
      }, 60);
    });
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${darkMode ? 'bg-gray-900 text-gray-200' : 'bg-gray-50 text-gray-800'} pb-20`}>
      {showGuide && <OnboardingGuide onClose={() => setShowGuide(false)} />}

      {/* Header */}
      <header className={`border-b transition-colors duration-300 sticky top-0 z-40 ${darkMode ? 'bg-gray-900/80 border-gray-800' : 'bg-white/80 border-gray-200'} backdrop-blur-md screenshot-hide`}>
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 group cursor-pointer">
            <div className="relative w-9 h-9">
              <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-sm">
                <defs>
                  <linearGradient id="logoGradient" x1="0%" y1="0%" x2="100%" y2="100%">
                    <stop offset="0%" stopColor="#f59e0b" />
                    <stop offset="100%" stopColor="#ea580c" />
                  </linearGradient>
                </defs>
                <path 
                  d="M20 20 C20 20 50 10 80 20 L80 50 C80 75 50 90 50 90 C50 90 20 75 20 50 Z" 
                  fill="none" 
                  stroke="url(#logoGradient)" 
                  strokeWidth="8" 
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
                <path 
                  d="M35 60 L50 75 L90 25 M90 25 L75 25 M90 25 L90 40" 
                  fill="none" 
                  stroke="url(#logoGradient)" 
                  strokeWidth="10" 
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </div>
            <h1 className="text-2xl font-black tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-orange-600 to-indigo-500">
              Bharat Wealth
            </h1>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={() => setShowGuide(true)}
              className={`p-2 rounded-xl transition-all ${darkMode ? 'bg-gray-800 text-gray-400' : 'bg-gray-100 text-gray-500'} hover:scale-110 active:scale-95`}
              aria-label="Show user guide"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
