  const [aiInsight, setAiInsight] = useState<AIInsight | null>(null);
  const [aiError, setAiError] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isCapturing, setIsCapturing] = useState(false);
  const [showGuide, setShowGuide] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [darkMode]);

  const results = useMemo(() => calculateWealth(inputs), [inputs]);

  const handleGetInsights = async () => {
    setIsGenerating(true);
    setAiInsight(null);
    setAiError(null);
    try {
      const insight = await getFinancialInsights(inputs, results);
      if (insight) {
        setAiInsight(insight);
      } else {
        setAiError("Unable to connect to AI advisor. Please try again.");
      }
    } catch (error) {
      setAiError("Unable to connect to AI advisor. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleReset = () => {
    setInputs(DEFAULT_INPUTS);
    setAiInsight(null);
    setAiError(null);
  };

  const handleDownloadImage = async () => {
    if (!reportRef.current || isCapturing) return;
    setIsCapturing(true);

    requestAnimationFrame(() => {
      setTimeout(async () => {
        try {
          const canvas = await html2canvas(reportRef.current!, {
            scale: 2,
            logging: false,
            useCORS: true,
            allowTaint: true,
            onclone: (clonedDoc) => {
              const clonedContainer = clonedDoc.getElementById('professional-report-container');
              const clonedProHeader = clonedDoc.getElementById('report-header-professional');
              const isDark = document.documentElement.classList.contains('dark');

              const gridSvgLight = `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%239CA3AF' fill-opacity='0.04'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`;
              const gridSvgDark = `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23E5E7EB' fill-opacity='0.04'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`;

              if (clonedContainer) {
                clonedContainer.style.padding = '48px';
                clonedContainer.style.borderRadius = '0px';
                clonedContainer.style.backgroundColor = isDark ? '#111827' : '#f9fafb';
                clonedContainer.style.backgroundImage = isDark ? gridSvgDark : gridSvgLight;

                if (clonedProHeader) {
                  clonedProHeader.style.display = 'flex';
                  clonedProHeader.style.marginBottom = '32px';
                }

                const screenshotHides = clonedDoc.querySelectorAll('.screenshot-hide');
                screenshotHides.forEach(el => (el as HTMLElement).style.display = 'none');
              }
            }
          });

          const image = canvas.toDataURL("image/png", 0.95);
          const link = document.createElement('a');
          link.download = `BharatWealth_${inputs.mode}_Report_${new Date().toISOString().split('T')[0]}.png`;
          link.href = image;
          link.click();
        } catch (err) {
          console.error("Professional report capture failed:", err);
        } finally {
          setIsCapturing(false);
        }
      }, 60);
    });
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${darkMode ? 'bg-gray-900 text-gray-200' : 'bg-gray-50 text-gray-800'} pb-20`}>
      {showGuide && <OnboardingGuide onClose={() => setShowGuide(false)} />}

      {/* Header */}
      <header className={`border-b transition-colors duration-300 sticky top-0 z-40 ${darkMode ? 'bg-gray-900/80 border-gray-800' : 'bg-white/80 border-gray-200'} backdrop-blur-md screenshot-hide`}>
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 group cursor-pointer">
            <div className="relative w-9 h-9">
              <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-sm">
                <defs>
                  <linearGradient id="logoGradient" x1="0%" y1="0%" x2="100%" y2="100%">
                    <stop offset="0%" stopColor="#f59e0b" />
                    <stop offset="100%" stopColor="#ea580c" />
                  </linearGradient>
                </defs>
                <path 
                  d="M20 20 C20 20 50 10 80 20 L80 50 C80 75 50 90 50 90 C50 90 20 75 20 50 Z" 
                  fill="none" 
                  stroke="url(#logoGradient)" 
                  strokeWidth="8" 
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
                <path 
                  d="M35 60 L50 75 L90 25 M90 25 L75 25 M90 25 L90 40" 
                  fill="none" 
                  stroke="url(#logoGradient)" 
                  strokeWidth="10" 
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </div>
            <h1 className="text-2xl font-black tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-orange-600 to-indigo-500">
              Bharat Wealth
            </h1>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={() => setShowGuide(true)}
              className={`p-2 rounded-xl transition-all ${darkMode ? 'bg-gray-800 text-gray-400' : 'bg-gray-100 text-gray-500'} hover:scale-110 active:scale-95`}
              aria-label="Show user guide"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className={`p-2 rounded-xl transition-all ${darkMode ? 'bg-gray-800 text-amber-400' : 'bg-gray-100 text-gray-500'} hover:scale-110 active:scale-95`}
              aria-label="Toggle Dark Mode"
            >
              {darkMode ? (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 9h-1m15.364-6.364l-.707.707M6.343 17.657l-.707.707M16.95 16.95l.707.707M7.05 7.05l.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
                </svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
                </svg>
              )}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Inputs */}
          <div className="lg:col-span-4 space-y-6 screenshot-hide">
            <InputSection inputs={inputs} setInputs={setInputs} onReset={handleReset} />

            <div className="p-6 rounded-2xl shadow-xl space-y-4 transition-colors bg-gradient-to-br from-indigo-800 to-indigo-900 text-white">
              <h3 className="text-lg font-semibold flex items-center gap-2 text-white">
                <span className="animate-pulse">✨</span> {inputs.mode} Analysis
              </h3>
              <p className="text-sm leading-relaxed text-indigo-200">
                Get a personalized strategy analysis from Gemini based on your {inputs.frequency.toLowerCase()} commitment.
              </p>
              <button
                onClick={handleGetInsights}
                disabled={isGenerating}
                className="w-full py-3 px-4 font-bold rounded-xl transition-all flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed shadow-lg bg-white text-indigo-800 hover:bg-indigo-50"
              >
                {isGenerating ? (
                  <>
                    <svg className="animate-spin h-5 w-5 mr-3" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Analyzing...
                  </>
                ) : (
                  `Analyze ${inputs.mode} Plan`
                )}
              </button>
            </div>
          </div>

          {/* Right Column: Results & Analysis (THE REPORT) */}
          <div 
            className="lg:col-span-8 space-y-8 rounded-3xl" 
            ref={reportRef}
            id="professional-report-container"
          >
            {/* Professional Report Header - Controlled via 'onclone' */}
            <div id="report-header-professional" style={{ display: 'none' }} className="flex-col gap-6 pb-8 border-b border-gray-200 dark:border-gray-700">
              <div className="flex justify-between items-start">
                <div>
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-8 h-8">
                      <svg viewBox="0 0 100 100" className="w-full h-full">
                        <path d="M20 20 C20 20 50 10 80 20 L80 50 C80 75 50 90 50 90 C50 90 20 75 20 50 Z" fill="none" stroke="#ea580c" strokeWidth="8" />
                        <path d="M35 60 L50 75 L90 25" fill="none" stroke="#ea580c" strokeWidth="10" />
                      </svg>
                    </div>
                    <h1 className="text-xl font-bold text-gray-800 dark:text-gray-100 uppercase tracking-wider">Bharat Wealth</h1>
                  </div>
                  <h2 className="text-3xl font-bold text-indigo-600 dark:text-indigo-400">Personalized Investment Report</h2>
                  <p className="text-sm text-gray-500 font-medium">Generated on {new Date().toLocaleDateString('en-IN', { dateStyle: 'long' })}</p>
                </div>
                <div className="text-right">
                  <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 dark:text-indigo-400 text-xs font-bold uppercase tracking-widest border border-indigo-100 dark:border-indigo-800">
                    {inputs.mode} Projection
                  </span>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-4 bg-gray-50 dark:bg-gray-800/50 p-4 rounded-2xl border border-gray-100 dark:border-gray-700 mt-4">
                <div>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1">Capital Commitment</p>
                  <p className="text-lg font-bold text-gray-800 dark:text-gray-100">₹{inputs.investmentAmount.toLocaleString('en-IN')} <span className="text-xs font-medium text-gray-500">/{inputs.mode === 'SIP' ? inputs.frequency : 'Once'}</span></p>
                </div>
                <div>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1">Expected Return</p>
                  <p className="text-lg font-bold text-emerald-600 dark:text-emerald-400">{inputs.expectedReturn}% <span className="text-xs font-medium text-gray-500">p.a.</span></p>
                </div>
                <div>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1">Tenure</p>
                  <p className="text-lg font-bold text-amber-600 dark:text-amber-400">{inputs.periodYears} <span className="text-xs font-medium text-gray-500">Years</span></p>
                </div>
              </div>
            </div>

            {/* Standard Dashboard Header (Visible only on web) */}
            <div className={`flex justify-between items-center mb-[-1.5rem] screenshot-hide`}>
              <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-2">Investment Performance</h2>
              <button 
                onClick={handleDownloadImage}
                disabled={isCapturing}
                className={`p-2.5 rounded-xl transition-all min-w-[120px] flex items-center justify-center ${darkMode ? 'bg-gray-800 text-indigo-400 hover:bg-indigo-800 hover:text-white' : 'bg-white text-indigo-600 hover:bg-indigo-600 hover:text-white shadow-sm border border-gray-200'} ${isCapturing ? 'opacity-80 cursor-wait' : 'hover:scale-105 active:scale-95'}`}
                title="Download Professional Report"
              >
                {isCapturing ? (
                  <div className="flex items-center gap-2">
                    <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    <span className="text-xs font-bold uppercase tracking-tight">Wait...</span>
                  </div>
                ) : (
                  <div className="flex items-center gap-2 px-1">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 002-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                    <span className="text-xs font-bold uppercase tracking-tight">Report</span>
                  </div>
                )}
              </button>
            </div>

            <ResultCards results={results} />

            <ChartsSection results={results} />

            {/* AI Insights Display */}
            {(aiInsight || isGenerating || aiError) && (
              <div className={`p-8 rounded-2xl shadow-sm border transition-colors duration-500 ${darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200/80'}`}>
                <div className="flex items-center gap-3 mb-4">
                  <span className="text-2xl">✨</span>
                  <h3 className={`text-xl font-bold ${darkMode ? 'text-gray-100' : 'text-gray-800'}`}>AI Smart Analysis</h3>
                </div>
                {isGenerating ? (
                  <div className="space-y-4">
                    <div className={`h-4 rounded w-3/4 animate-pulse ${darkMode ? 'bg-gray-700' : 'bg-gray-200'}`}></div>
                    <div className={`h-4 rounded w-full animate-pulse ${darkMode ? 'bg-gray-700' : 'bg-gray-200'}`}></div>
                    <div className="pt-2">
                        <div className={`h-6 rounded w-1/2 animate-pulse ${darkMode ? 'bg-gray-700' : 'bg-gray-200'}`}></div>
                    </div>
                  </div>
                ) : aiError ? (
                  <div className="text-center py-4">
                    <p className="text-red-500 dark:text-red-400">{aiError}</p>
                  </div>
                ) : aiInsight ? (
                  <div className="space-y-5 text-sm">
                    <p className="text-gray-600 dark:text-gray-300 leading-relaxed">{aiInsight.analysis}</p>

                    <div className="p-4 rounded-xl border bg-emerald-50 border-emerald-200 dark:bg-emerald-900/20 dark:border-emerald-800/50">
                      <div className="flex items-start gap-3">
                        <div className="flex-shrink-0 text-emerald-500 dark:text-emerald-400 mt-0.5">
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                          </svg>
                        </div>
                        <div>
                          <h4 className="font-bold text-emerald-800 dark:text-emerald-300 mb-1">Pro Tip</h4>
                          <p className="text-emerald-700 dark:text-emerald-300/90 leading-relaxed">{aiInsight.proTip}</p>
                        </div>
                      </div>
                    </div>

                    <div className="p-4 rounded-xl border bg-amber-50 border-amber-200 dark:bg-amber-900/20 dark:border-amber-800/50">
                       <div className="flex items-start gap-3">
                        <div className="flex-shrink-0 text-amber-500 dark:text-amber-400 mt-0.5">
                           <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 3.001-1.742 3.001H4.42c-1.53 0-2.493-1.667-1.743-3.001l5.58-9.92zM10 13a1 1 0 110-2 1 1 0 010 2zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                          </svg>
                        </div>
                        <div>
                          <h4 className="font-bold text-amber-800 dark:text-amber-300 mb-1">Consideration</h4>
                          <p className="text-amber-700 dark:text-amber-300/90 leading-relaxed">{aiInsight.warning}</p>
                        </div>
                      </div>
                    </div>
                  </div>
                ) : null}
              </div>
            )}


            {/* Summary Text (Professional styling) */}
            <div className={`wealth-verdict-container p-8 rounded-3xl border transition-colors ${darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200/80'}`}>
              <div className="flex flex-col md:flex-row gap-6 items-center">
                <div className={`hidden md:flex p-4 rounded-2xl ${darkMode ? 'bg-gray-700/50 text-indigo-400' : 'bg-indigo-100/70 text-indigo-600'}`}>
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" />
                  </svg>
                </div>
                <div>
                  <h4 className={`font-bold mb-2 uppercase tracking-widest text-xs ${darkMode ? 'text-indigo-400' : 'text-indigo-600'}`}>The Wealth Verdict</h4>
                  <p className={`text-lg leading-snug ${darkMode ? 'text-gray-200' : 'text-gray-700'}`}>
                    Investing <span className="font-bold underline decoration-2 underline-offset-4">₹{inputs.investmentAmount.toLocaleString('en-IN')}</span> {inputs.mode === 'SIP' ? inputs.frequency.toLowerCase() : 'lumpsum'} for <span className="font-bold">{inputs.periodYears} years</span>, 
                    yields a potential total of <span className="font-bold text-2xl">₹{results.totalValue.toLocaleString('en-IN')}</span>. 
                    Your capital multiplies with estimated returns of <span className="font-bold">₹{results.estimatedReturns.toLocaleString('en-IN')}</span>.
                  </p>
                </div>
              </div>
            </div>

            <div className={`pt-6 border-t ${darkMode ? 'border-gray-800' : 'border-gray-200'}`}>
              <p className="text-[10px] text-gray-500 text-center uppercase tracking-wider leading-tight italic">
                Disclaimer: This report is generated by Bharat Wealth for educational purposes. Mutual fund investments are subject to market risks. Past performance does not guarantee future results.
              </p>
            </div>
          </div>
        </div>
      </main>

      <footer className="max-w-6xl mx-auto px-4 mt-12 text-center text-gray-500 text-xs pb-10 screenshot-hide">
        <p className="mb-2">Built with ❤️ in India for the World</p>
        <p>© {new Date().getFullYear()} Bharat Wealth. All calculations are for illustrative purposes.</p>
      </footer>
    </div>
  );
};

export default App;

