                {/* @ts-expect-error The `activeIndex` prop is valid for recharts Pie component, but the type definitions might be out of sync. */}
                <Pie
                  activeIndex={activeIndex}
                  activeShape={renderActiveShape}
                  onMouseEnter={onPieEnter}
