import React, { useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, AreaChart, Area, XAxis, YAxis, CartesianGrid, Sector } from 'recharts';
import { SIPResults } from '../types';

interface Props {
  results: SIPResults;
}

const ChartsSection: React.FC<Props> = ({ results }) => {
  const [showInvestedLine, setShowInvestedLine] = useState(true);
  const [activeIndex, setActiveIndex] = useState(0);

  const pieData = [
    { name: 'Invested Amount', value: results.totalInvested },
    { name: 'Estimated Returns', value: results.estimatedReturns },
  ];

  const COLORS = ['#6366f1', '#10b981'];

  const renderActiveShape = (props: any) => {
    const { cx, cy, innerRadius, outerRadius, startAngle, endAngle, fill } = props;
    return (
      <g>
        <Sector
          cx={cx}
          cy={cy}
          innerRadius={innerRadius}
          outerRadius={outerRadius + 6}
          startAngle={startAngle}
          endAngle={endAngle}
          fill={fill}
          stroke={fill}
          strokeWidth={1}
          style={{ filter: `drop-shadow(0px 4px 8px ${fill}55)` }}
        />
      </g>
    );
  };

  const onPieEnter = (_: any, index: number) => {
    setActiveIndex(index);
  };


  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="p-4 rounded-xl shadow-xl border backdrop-blur-sm transition-colors dark:bg-gray-900/80 dark:border-gray-700 bg-gray-50/80 border-gray-200">
          <p className="text-sm font-bold text-gray-600 dark:text-gray-300 mb-2">Year {label}</p>
          {payload.map((entry: any, index: number) => (
            <div key={index} className="flex items-center gap-3 justify-between">
              <span className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full" style={{ backgroundColor: entry.color || entry.stroke }}></div>
                <span className="text-xs font-medium dark:text-gray-400 text-gray-500">{entry.name}:</span>
              </span>
              <span className="text-sm font-bold dark:text-gray-100 text-gray-900">
                ₹{entry.value.toLocaleString('en-IN')}
              </span>
            </div>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Wealth Distribution (Pie) */}
        <div className="p-6 rounded-2xl shadow-sm border transition-all hover:shadow-lg dark:bg-gray-800 dark:border-gray-700 bg-white border-gray-200/80">
          <h3 className="text-lg font-bold dark:text-gray-100 text-gray-800 mb-4 flex items-center gap-2">
            <span className="w-1 h-4 bg-emerald-500 rounded-full"></span>
            Wealth Composition
          </h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                {/* FIX: The `activeIndex` prop is valid for the Pie component, but the type definitions for recharts might be out of sync. */}
                {/* @ts-expect-error */}
                <Pie
                  activeIndex={activeIndex}
                  activeShape={renderActiveShape}
                  onMouseEnter={onPieEnter}
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={8}
                  dataKey="value"
                  animationBegin={0}
                  animationDuration={1500}
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} strokeWidth={0} />
                  ))}
                </Pie>
                <Tooltip 
                  formatter={(value: number) => `₹${value.toLocaleString('en-IN')}`}
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Growth Projection (Area) */}
        <div className="p-6 rounded-2xl shadow-sm border transition-all hover:shadow-lg dark:bg-gray-800 dark:border-gray-700 bg-white border-gray-200/80">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
            <h3 className="text-lg font-bold dark:text-gray-100 text-gray-800 flex items-center gap-2">
              <span className="w-1 h-4 bg-indigo-500 rounded-full"></span>
              Growth Projection
            </h3>

            <button 
              onClick={() => setShowInvestedLine(!showInvestedLine)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                showInvestedLine 
                  ? 'dark:bg-gray-700 dark:text-gray-400 bg-gray-100 text-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600' 
                  : 'dark:bg-indigo-900/30 dark:text-indigo-400 bg-indigo-50 text-indigo-600 hover:bg-indigo-100'
              }`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5" viewBox="0 0 20 20" fill="currentColor">
                {showInvestedLine ? (
                  <path fillRule="evenodd" d="M3.707 2.293a1 1 0 00-1.414 1.414l14 14a1 1 0 001.414-1.414l-1.473-1.473A10.014 10.014 0 0019.542 10C18.268 5.943 14.478 3 10 3a9.958 9.958 0 00-4.512 1.074l-1.78-1.781zm4.261 4.26a4 4 0 015.493 5.493l-5.493-5.493z" clipRule="evenodd" />
                ) : (
                  <path d="M10 12a2 2 0 100-4 2 2 0 000 4z" />
                )}
                <path fillRule="evenodd" d="M.458 10C1.732 5.943 5.522 3 10 3c2.11 0 4.041.665 5.624 1.797l-1.414 1.414A7.963 7.963 0 0010 5C6.333 5 3.393 7.42 2.146 10c.484 1.002 1.144 1.884 1.938 2.606L2.67 14.02A9.978 9.978 0 01.458 10z" clipRule="evenodd" />
              </svg>
              {showInvestedLine ? 'Hide Principal' : 'Show Principal'}
            </button>
          </div>

          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={results.yearlyData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                <defs>
                  <linearGradient id="colorValue" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#6366f1" stopOpacity={0.15}/>
                    <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="currentColor" opacity={0.08} />
                <XAxis 
                  dataKey="year" 
                  tick={{ fontSize: 11, fill: '#6b7280' }} 
                  axisLine={false} 
                  tickLine={false}
                  padding={{ left: 10, right: 10 }}
                />
                <YAxis 
                  tick={{ fontSize: 10, fill: '#9ca3af' }} 
                  axisLine={false} 
                  tickLine={false} 
                  tickFormatter={(val) => {
                    if (val >= 10000000) return `₹${(val / 10000000).toFixed(1)}Cr`;
                    if (val >= 100000) return `₹${(val / 100000).toFixed(1)}L`;
                    if (val >= 1000) return `₹${(val / 1000).toFixed(0)}k`;
                    return `₹${val}`;
                  }}
                />
                <Tooltip content={<CustomTooltip />} />
                <Area 
                  type="monotone" 
                  dataKey="totalValue" 
                  stroke="#6366f1" 
                  strokeWidth={3} 
                  fillOpacity={1} 
                  fill="url(#colorValue)" 
                  name="Total Wealth"
                  activeDot={{ r: 6, stroke: 'var(--card-bg, #fff)', strokeWidth: 2 }}
                  animationDuration={1500}
                  // FIX: `animationTimingFunction` is not a valid prop for Area. Use `animationEasing` instead.
                  animationEasing="ease-in-out"
                />
                <Area 
                  type="monotone" 
                  dataKey="invested" 
                  stroke="#6b7280" 
                  strokeWidth={2} 
                  fillOpacity={0} 
                  name="Invested Amount"
                  hide={!showInvestedLine}
                  activeDot={{ r: 4, stroke: 'var(--card-bg, #fff)', strokeWidth: 2 }}
                  animationDuration={1000}
                  // FIX: `animationTimingFunction` is not a valid prop for Area. Use `animationEasing` instead.
                  animationEasing="ease-in-out"
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChartsSection;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { SIPInputs, SIPResults, AIInsight } from './types';
import { calculateWealth, formatCurrency } from './utils/sipCalculations';
import { getFinancialInsights } from './services/geminiService';
import InputSection from './components/InputSection';
import ResultCards from './components/ResultCards';
import ChartsSection from './components/ChartsSection';
import OnboardingGuide from './components/OnboardingGuide';
import ShareModal from './components/ShareModal';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

const DEFAULT_INPUTS: SIPInputs = {
  investmentAmount: 5000,
  expectedReturn: 12,
  periodYears: 10,
  mode: 'SIP',
  frequency: 'Monthly'
};

const App: React.FC = () => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [darkMode, setDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark';
    }
    return false;
  });

  const [inputs, setInputs] = useState<SIPInputs>(DEFAULT_INPUTS);

  const [aiInsight, setAiInsight] = useState<AIInsight | null>(null);
  const [aiError, setAiError] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isCapturing, setIsCapturing] = useState(false);
  const [showGuide, setShowGuide] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [darkMode]);

  const results = useMemo(() => calculateWealth(inputs), [inputs]);

  const handleGetInsights = async () => {
    setIsGenerating(true);
    setAiInsight(null);
    setAiError(null);
    try {
      const insight = await getFinancialInsights(inputs, results);
      if (insight) {
        setAiInsight(insight);
      } else {
        setAiError("Unable to connect to AI advisor. Please try again.");
      }
    } catch (error) {
      setAiError("Unable to connect to AI advisor. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleReset = () => {
    setInputs(DEFAULT_INPUTS);
    setAiInsight(null);
    setAiError(null);
  };

  const handleDownloadPdf = async () => {
    if (!reportRef.current || isCapturing) return;
    setIsCapturing(true);

    // Use a short timeout to allow the UI to update to the 'capturing' state
    setTimeout(async () => {
      try {
        const canvas = await html2canvas(reportRef.current!, {
          scale: 2, // Higher scale for better quality
          logging: false,
          useCORS: true,
          allowTaint: true,
          onclone: (clonedDoc) => {
            const clonedContainer = clonedDoc.getElementById('professional-report-container');
            const clonedProHeader = clonedDoc.getElementById('report-header-professional');
            const isDark = document.documentElement.classList.contains('dark');

            const gridSvgLight = `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%239CA3AF' fill-opacity='0.04'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`;
            const gridSvgDark = `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23E5E7EB' fill-opacity='0.04'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`;

            if (clonedContainer) {
              clonedContainer.style.padding = '48px';
              clonedContainer.style.borderRadius = '0px';
              clonedContainer.style.backgroundColor = isDark ? '#111827' : '#f9fafb';
              clonedContainer.style.backgroundImage = isDark ? gridSvgDark : gridSvgLight;

              if (clonedProHeader) {
                clonedProHeader.style.display = 'flex';
                clonedProHeader.style.marginBottom = '32px';
              }

              const screenshotHides = clonedDoc.querySelectorAll('.screenshot-hide');
              screenshotHides.forEach(el => (el as HTMLElement).style.display = 'none');
            }
          }
        });

        const image = canvas.toDataURL("image/png", 0.95);
        const pdf = new jsPDF('p', 'mm', 'a4');

        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const canvasWidth = canvas.width;
        const canvasHeight = canvas.height;
        const ratio = canvasWidth / canvasHeight;

        let imgWidth = pdfWidth - 20; // with margin
        let imgHeight = imgWidth / ratio;

        if (imgHeight > pdfHeight - 20) {
            imgHeight = pdfHeight - 20;
            imgWidth = imgHeight * ratio;
        }

        const x = (pdfWidth - imgWidth) / 2;
        const y = 10;

        pdf.addImage(image, 'PNG', x, y, imgWidth, imgHeight);

        const fileName = `BharatWealth_${inputs.mode}_Report_${new Date().toISOString().split('T')[0]}.pdf`;
        pdf.save(fileName);

      } catch (err) {
        console.error("PDF report capture failed:", err);
      } finally {
        setIsCapturing(false);
      }
    }, 100);
  };

  const shareText = useMemo(() => {
    const { investmentAmount, frequency, periodYears, mode } = inputs;
    const { totalValue } = results;

    const amountStr = formatCurrency(investmentAmount);
    const totalValStr = formatCurrency(totalValue);
    const freqStr = mode === 'SIP' ? frequency.toLowerCase() : 'one-time';

    return `Just projected my wealth growth with Bharat Wealth! Investing ${amountStr} ${freqStr} for ${periodYears} years could grow to ${totalValStr}. Plan your financial future too! #BharatWealth #Investment #SIP #FinancialPlanning`;
  }, [inputs, results]);


  return (
    <div className={`min-h-screen transition-colors duration-300 ${darkMode ? 'bg-gray-900 text-gray-200' : 'bg-gray-50 text-gray-800'} pb-20`}>
      {showGuide && <OnboardingGuide onClose={() => setShowGuide(false)} />}
      {showShareModal && <ShareModal onClose={() => setShowShareModal(false)} shareText={shareText} appUrl="https://main--delightful-cendol-8c630f.netlify.app/" />}

      {/* Header */}
      <header className={`border-b transition-colors duration-300 sticky top-0 z-40 ${darkMode ? 'bg-gray-900/80 border-gray-800' : 'bg-white/80 border-gray-200'} backdrop-blur-md screenshot-hide`}>
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 group cursor-pointer">
            <div className="relative w-9 h-9">
              <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-sm">
                <defs>
                  <linearGradient id="logoGradient" x1="0%" y1="0%" x2="100%" y2="100%">
                    <stop offset="0%" stopColor="#f59e0b" />
                    <stop offset="100%" stopColor="#ea580c" />
                  </linearGradient>
                </defs>
                <path 
                  d="M20 20 C20 20 50 10 80 20 L80 50 C80 75 50 90 50 90 C50 90 20 75 20 50 Z" 
                  fill="none" 
                  stroke="url(#logoGradient)" 
                  strokeWidth="8" 
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
                <path 
                  d="M35 60 L50 75 L90 25 M90 25 L75 25 M90 25 L90 40" 
                  fill="none" 
                  stroke="url(#logoGradient)" 
                  strokeWidth="10" 
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </div>
            <h1 className="text-2xl font-black tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-orange-600 to-indigo-500">
              Bharat Wealth
            </h1>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={() => setShowGuide(true)}
              className={`p-2 rounded-xl transition-all ${darkMode ? 'bg-gray-800 text-gray-400' : 'bg-gray-100 text-gray-500'} hover:scale-110 active:scale-95`}
              aria-label="Show user guide"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </button>
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className={`p-2 rounded-xl transition-all ${darkMode ? 'bg-gray-800 text-amber-400' : 'bg-gray-100 text-gray-500'} hover:scale-110 active:scale-95`}
              aria-label="Toggle Dark Mode"
            >
              {darkMode ? (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 9h-1m15.364-6.364l-.707.707M6.343 17.657l-.707.707M16.95 16.95l.707.707M7.05 7.05l.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
                </svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
                </svg>
              )}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Inputs */}
          <div className="lg:col-span-4 space-y-6 screenshot-hide">
            <InputSection inputs={inputs} setInputs={setInputs} onReset={handleReset} />

            <div className="p-6 rounded-2xl shadow-xl space-y-4 transition-colors bg-gradient-to-br from-indigo-800 to-indigo-900 text-white">
              <h3 className="text-lg font-semibold flex items-center gap-2 text-white">
                <span className="animate-pulse">✨</span> {inputs.mode} Analysis
              </h3>
              <p className="text-sm leading-relaxed text-indigo-200">
                Get a personalized strategy analysis from Gemini based on your {inputs.frequency.toLowerCase()} commitment.
              </p>
              <button
                onClick={handleGetInsights}
                disabled={isGenerating}
                className="w-full py-3 px-4 font-bold rounded-xl transition-all flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed shadow-lg bg-white text-indigo-800 hover:bg-indigo-50"
              >
                {isGenerating ? (
                  <>
                    <svg className="animate-spin h-5 w-5 mr-3" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Analyzing...
                  </>
                ) : (
                  `Analyze ${inputs.mode} Plan`
                )}
              </button>
            </div>
          </div>

          {/* Right Column: Results & Analysis (THE REPORT) */}
          <div 
            className="lg:col-span-8 space-y-8 rounded-3xl" 
            ref={reportRef}
            id="professional-report-container"
          >
            {/* Professional Report Header - Controlled via 'onclone' */}
            <div id="report-header-professional" style={{ display: 'none' }} className="flex-col gap-6 pb-8 border-b border-gray-200 dark:border-gray-700">
              <div className="flex justify-between items-start">
                <div>
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-8 h-8">
                      <svg viewBox="0 0 100 100" className="w-full h-full">
