  const handlePointerDown = (e: React.PointerEvent<HTMLInputElement>) => {
    const input = e.currentTarget;
    const rect = input.getBoundingClientRect();
    const min = parseFloat(input.min);
    const max = parseFloat(input.max);
    const value = parseFloat(input.value);

    // Approximate thumb position (0 to 1)
    const percent = (value - min) / (max - min);

    // Convert to pixels relative to the input element
    // Note: Standard range inputs have some padding/margin for the thumb
    const thumbX = percent * rect.width;
    const clickX = e.clientX - rect.left;

    // Use a threshold (25px radius) to detect if the click is on the thumb
    const threshold = 25; 
    if (Math.abs(clickX - thumbX) > threshold) {
      e.preventDefault();
    }
  };

