    if (!pdfTemplateRef.current || isCapturing) return;
    setIsCapturing(true);

    // Allow a small tick for the hidden element to be prepared for cloning
    await new Promise(r => setTimeout(r, 100));

    try {
      const canvas = await html2canvas(pdfTemplateRef.current, {
        scale: 3, // Ultra-high resolution for printing
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff', // Always white for formal A4
        onclone: (clonedDoc) => {
          const el = clonedDoc.getElementById('pdf-report-hidden-template');
          if (el) el.style.display = 'block';
        }
      });

      const imgData = canvas.toDataURL('image/png', 1.0);
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
      });

      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`BharatWealth_Report_${new Date().getTime()}.pdf`);
    } catch (err) {
      console.error("PDF Generation Error:", err);
    } finally {
      setIsCapturing(false);
